*/ size(100); defaultpen(linewidth(0.7)); real sx = 0.6, sy = 0.2;
path f1 = (0,0)--(1,1.7)--(3,1.7)--(2,0)--cycle;
filldraw(f1, rgb(0.9,0.9,0.9));
path f2=(1,1.7)--(1,0);
draw(f2);
label("$A$",(0,0),SW);
label("$B$",(2,0),SE);
label("$C$",(3,1.7),NE);
label("$D$",(1,1.7),NW);
label("$E$",(1,0),S);

[/asy]

